DISCOUNT_RATES = {'basic': 0, 'premium': 0.15, 'enterprise': 0.3}

def process_payment(user, cart, payment_details):
    total = sum(item['price'] for item in cart)
    discount = DISCOUNT_RATES[user['role']] * total
    adjusted_total = total - discount
    # assuming pay function receives the amount and other necessary details
    return pay({'amount': adjusted_total}, payment_details)